#include <bits/stdc++.h>
using namespace std;

long long solve(long long n, long long m, long long k) {
    if (k == 0) return n * m;
    if (n == 1 && m == 1) return 1;
    if (k >= min(n, m) / 2) return 1;

    long long res = 0;
    long long rows = n, cols = m;

    while (rows > 0 && cols > 0) {
        res += 2;
        rows -= 2 * k;
        cols -= 2 * k;
    }

    if (rows > 0) res += 1;
    if (cols > 0) res += 1;

    return res;
}
